class Solution:
    def maxPointsInsideSquare(self, points, s: str) -> int:
        # Try all possible half-sides L = max(|x|,|y|) for each point
        # Binary search on L
        n = len(points)
        dists = [max(abs(points[i][0]), abs(points[i][1])) for i in range(n)]
        def count_at(L):
            seen = {}
            for i in range(n):
                if dists[i] <= L:
                    c = s[i]
                    if c in seen:
                        return -1  # duplicate
                    seen[c] = i
            return len(seen)

        # Collect all possible L values
        all_L = sorted(set(dists))
        result = 0
        for L in all_L:
            c = count_at(L)
            if c == -1:
                break
            result = c
        return result

