class Solution:
    def maxPointsInsideSquare(self, points, s: str) -> int:
        n = len(points)
        dists = [(max(abs(points[i][0]), abs(points[i][1])), s[i]) for i in range(n)]
        dists.sort()
        seen = {}
        result = 0
        i = 0
        while i < n:
            # collect all points at this distance level
            cur_d = dists[i][0]
            j = i
            level = []
            while j < n and dists[j][0] == cur_d:
                level.append(dists[j][1])
                j += 1
            # check if adding this level creates a duplicate
            tag_count = {}
            for c in level:
                tag_count[c] = tag_count.get(c, 0) + 1
            conflict = any(v > 1 for v in tag_count.values()) or any(c in seen for c in level)
            if conflict:
                break
            for c in level:
                seen[c] = True
            result += len(level)
            i = j
        return result

