var maxPointsInsideSquare = function(points, s) {
    const n = points.length;
    const dists = points.map((p, i) => [Math.max(Math.abs(p[0]), Math.abs(p[1])), s[i]]);
    dists.sort((a, b) => a[0] - b[0]);
    const seen = new Set();
    let result = 0;
    let i = 0;
    while (i < n) {
        const curD = dists[i][0];
        let j = i;
        const level = [];
        while (j < n && dists[j][0] === curD) {
            level.push(dists[j][1]);
            j++;
        }
        const tagCount = {};
        for (const c of level) tagCount[c] = (tagCount[c] || 0) + 1;
        const conflict = level.some(c => seen.has(c)) || Object.values(tagCount).some(v => v > 1);
        if (conflict) break;
        for (const c of level) seen.add(c);
        result += level.length;
        i = j;
    }
    return result;
};
